input.new_string:
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const processScenario = (scenario: Scenario): ScenarioOutput => {
  const results = scenario.steps.map((step) => {
    const s = step as { op: string; items: Array<{ type: string }> };
    const base = BASE_PREMIUMS[s.items[0].type];
    const premium = Math.ceil(base * 1.1) + 5;
    return { premium };
  });
  return { results };
};

