import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  it("should quote a single sword with base premium, first-insurance surcharge, and processing fee", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("should quote an amulet using its item-type pricing", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("should apply loyalty discount for customers with at least 2 years");
  it.todo("should add risk surcharge for cursed items");
  it.todo("should add risk surcharge for highly enchanted items (level >= 5)");
  it.todo("should apply bundle pricing for three alike components");
  it.todo("should apply deductible and return payout and remaining cap for a basic claim");
  it.todo("should cap claim payout at twice the policy insurance sum");
});

