        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("should apply loyalty discount for customers with at least 2 years");
  it.todo("should add risk surcharge for cursed items");
  it.todo("should add risk surcharge for highly enchanted items (level >= 5)");
  it.todo("should apply bundle pricing for three alike components");
  it.todo("should apply deductible and return payout and remaining cap for a basic claim");
  it.todo("should cap claim payout at twice the policy insurance sum");
});

